int calculateMaxCoins(int* balloonNumbers, int n) {
    int* nums = (int*)malloc((n + 2) * sizeof(int));
    nums[0] = 1;
    nums[n + 1] = 1;
    for (int i = 0; i < n; i++) {
        nums[i + 1] = balloonNumbers[i];
    }
    int** dp = (int**)malloc((n + 2) * sizeof(int*));
    for (int i = 0; i < n + 2; i++) {
        dp[i] = (int*)calloc(n + 2, sizeof(int));
    }
    for (int len = 1; len <= n; len++) {
        for (int left = 1; left <= n - len + 1; left++) {
            int right = left + len - 1;
            for (int k = left; k <= right; k++) {
                int coins = nums[left - 1] * nums[k] * nums[right + 1];
                int remaining = (k - 1 >= left) ? dp[left][k - 1] : 0;
                remaining += (k + 1 <= right) ? dp[k + 1][right] : 0;
                dp[left][right] = (dp[left][right] > coins + remaining) ? dp[left][right] : coins + remaining;
            }
        }
    }
    int result = dp[1][n];
    for (int i = 0; i < n + 2; i++) {
        free(dp[i]);
    }
    free(dp);
    free(nums);
    return result;
}

